views/recent-tasks.setup:
interface TaskRow { id: number; title: string; assigneeName: string; status: Status; priority: Priority; due: string }
const rows: TaskRow[] = INITIAL_TASKS.slice(0, 8).map(t => ({ id: t.id, title: t.title, assigneeName: MEMBERS.find(m => m.id === t.assignee)?.name ?? '', status: t.status, priority: t.priority, due: t.due }));
const columns = [
  { key: 'title', header: 'Task', width: 'w-[280px]', render: (row: TaskRow) => <p className="text-ui-fg-base txt-compact-small-plus">{row.title}</p> },
  { key: 'assignee', header: 'Assignee', width: 'w-[160px]', render: (row: TaskRow) => <p className="text-ui-fg-subtle txt-compact-small">{row.assigneeName}</p> },
  { key: 'status', header: 'Status', width: 'w-[140px]', render: (row: TaskRow) => <div className="flex gap-1 items-center"><StatusDot status={row.status} /><span className="text-ui-fg-subtle txt-compact-small">{STATUS_LABEL[row.status]}</span></div> },
  { key: 'priority', header: 'Priority', width: 'w-[100px]', render: (row: TaskRow) => <Badge size="2xsmall" color={PRIORITY_COLOR[row.priority]}>{row.priority.charAt(0).toUpperCase() + row.priority.slice(1)}</Badge> },
  { key: 'due', header: 'Due Date', width: 'w-[100px]', render: (row: TaskRow) => <p className={`txt-compact-small ${isOverdue(row.due) && row.status !== 'done' ? 'text-ui-fg-error' : 'text-ui-fg-subtle'}`}>{formatDueDate(row.due)}</p> },
];

views/kanban-board.setup:
const STATUSES: Status[] = ['todo', 'in_progress', 'in_review', 'done'];
const columns = STATUSES.map(s => {
  const tasks = INITIAL_TASKS.filter(t => t.status === s);
  return {
    status: s, label: STATUS_LABEL[s], count: tasks.length, statusIcon: <StatusDot status={s} />,
    cards: tasks.map(t => { const m = MEMBERS.find(mem => mem.id === t.assignee)!; return <KanbanCard key={t.id} title={t.title} desc={t.desc} member={{ initials: m.initials, avatarBg: m.avatarBg, avatarText: m.avatarText }} firstName={m.name.split(' ')[0]} dueDate={formatDueDate(t.due)} overdue={isOverdue(t.due) && t.status !== 'done'} priorityLabel={t.priority.charAt(0).toUpperCase() + t.priority.slice(1)} priorityColor={PRIORITY_COLOR[t.priority]} />; }),
  };
});

overlays/task-details-modal.setup:
const task = INITIAL_TASKS[0];
const assignee = MEMBERS.find(m => m.id === task.assignee)!;
const STATUS_BADGE_COLORS: Record<Status, { bg: string; border: string; text: string }> = {
  todo: { bg: 'var(--tag-neutral-bg)', border: 'var(--tag-neutral-border)', text: 'var(--tag-neutral-text)' },
  in_progress: { bg: 'var(--tag-blue-bg)', border: 'var(--tag-blue-border)', text: 'var(--tag-blue-text)' },
  in_review: { bg: 'var(--tag-orange-bg)', border: 'var(--tag-orange-border)', text: 'var(--tag-orange-text)' },
  done: { bg: 'var(--tag-green-bg)', border: 'var(--tag-green-border)', text: 'var(--tag-green-text)' },
};
const infoRows = [
  { label: 'Status', value: STATUS_LABEL[task.status], type: 'status' as const, statusColor: STATUS_BADGE_COLORS[task.status] },
  { label: 'Assignee', value: assignee.name, type: 'assignee' as const, member: { initials: assignee.initials, avatarBg: assignee.avatarBg, avatarText: assignee.avatarText } },
  { label: 'Due date', value: formatDueDate(task.due), type: 'date' as const, overdue: isOverdue(task.due) && task.status !== 'done' },
];
const activity = ACTIVITY.filter(a => a.taskId === task.id).map(a => { const m = MEMBERS.find(mem => mem.id === a.memberId)!; return { member: { initials: m.initials, avatarBg: m.avatarBg, avatarText: m.avatarText }, name: m.name, time: a.time, text: a.text }; });

